import microcoapy
from machine import Pin

temperatureSensor = machine.ADC(4)
led = machine.Pin(2, machine.Pin.OUT)

def receiveMessageCallback(packet, senderIp, senderPort):
    resourceName = packet.getUriPath().lower()
    
    if packet.isRequest():
        if resourceName == "/sensors/temp": 
            temperature = measure_temperature()  
            packet.setPayload(temperature)
            packet.setResponseCode(microcoapy.COAP.ResponseCode.COAP_CONTENT)
        elif resourceName == "/actuators/light":
            if packet.getCode() == microcoapy.COAP.POST:  
                status = packet.toString()
                led.value(1 if status.lower() == "on" else 0)  
                packet.setResponseCode(microcoapy.COAP.ResponseCode.COAP_CHANGED)
        else:
            packet.setResponseCode(microcoapy.COAP.ResponseCode.COAP_NOT_FOUND)
    server.sendResponse(senderIp, senderPort, packet)  

def measure_temperature():
    raw_data = temperatureSensor.read()  
    calibrated_data = raw_data * 3.3 / (1<<10)  
    temperature = (calibrated_data - 0.5) * 10  
    return str(temperature)

server = microcoapy.CoapServer()
server.addIncomingRequestCallback(receiveMessageCallback)
server.start()